INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (1, 0.029, 110, 122601, 1.5, 0, 1, 1, 101, 0, "仲間と夏を楽しむ、夏海の魔法士。自分を変えたいという固い決意で、障害物を無効化して走り続ける。", 160, 1, 105);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (2, 0.014, 105, 122401, 2.5, 1, 0, 2, 102, 0, "太陽よりも輝く、夏海の元気娘。　持ち前の身体能力で、どんなコースも柔軟に対応し、駆け抜ける。", 120, 3, 111);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (3, 0.017, 110, 122501, 2.5, 0, 0, 3, 103, 1, "波打ち際に煌めく、夏海の剣士。　日々の鍛錬で鍛えた脚で、長い距離も速度を落とさず走り切る。", 350, 2, 105);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (4, 0.016, 110, 107501, 1.5, 1, 0, 4, 104, 0, "海の幸に目がない、渚のお姫様。　『王家の装備』の力を解放し、障害物をものともせず前へと進む。", 130, 3, 105);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (5, 0.014, 110, 107601, 2.5, 0, 1, 5, 105, 0, "海でも主さまをお世話する、白浜の巫女。精霊の力で自身を加速させ、誰よりも速くゴールを目指す。", 160, 1, 105);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (6, 0.029, 120, 107801, 3.5, 0, 0, 6, 106, 1, "水着姿を恥じらう、ツンデレ猫娘。お得意の魔法で、対戦相手の走りを妨害し、レースを有利に進める。", 255, 2, 103);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (7, 0.013, 120, 110601, 3.5, 0, 1, 7, 107, 0, "優雅に浜を駆ける、真夏のマホ姫。しゃなりしゃなりと、雅な身のこなしで障害物を跳び越えていく。", 160, 1, 103);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (8, 0.014, 110, 110401, 2.5, 0, 0, 8, 108, 1, "浜の平和を守る、真夏の狼娘。　　獣人の強靭なスタミナで、レース　後半にスパートをかける。", 350, 2, 103);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (9, 0.012, 105, 110501, 1.5, 1, 0, 9, 109, 0, "浜に力強く舞う、真夏の南国娘。　レースの喧噪の中でも精神を乱さず後半に大きな捲りを見せる。", 130, 3, 100);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (10, 0.014, 105, 115701, 2.5, 0, 1, 10, 110, 0, "浜の事件を嗅ぎ付けた、真夏の　　名探偵。高い推理力と魔法で、的確に対戦相手の走りを乱す。", 200, 1, 103);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (11, 0.071, 105, 113601, 2.5, 0, 0, 11, 111, 1, "再び鎧を脱いだ、灼熱の騎士団長。実戦で培った判断力で、瞬時にバリアを展開し、障害物を無力化する。", 350, 2, 103);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (12, 0.014, 120, 107901, 1.5, 1, 0, 12, 112, 0, "水が苦手な、海辺の気まぐれ猫娘。浜に現れた美少女義賊は、対戦相手のスピードを奪いとる。", 130, 3, 103);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (13, 0.022, 110, 108001, 1.5, 0, 1, 13, 113, 0, "バカンスも効率第一な、海の傭兵。レースでも最高効率を求め、どんな状況でも隙のない走りを見せる。", 200, 2, 105);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (14, 0.031, 110, 110301, 2.5, 0, 1, 14, 114, 0, "真夏の太陽が良く似合う、海辺の　サレンママ。多才で器用、どんな　障害物もエレガントに越えていく。", 160, 1, 108);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (15, 0.036, 110, 107701, 0.5, 1, 0, 15, 115, 0, "海に嵐を呼ぶ夏のドジっ娘メイド。日頃から災難に慣れており、多少　のトラブルには動じたりしない。", 130, 1, 105);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (16, 0.048, 110, 113101, 3.5, 0, 0, 16, 116, 1, "粋な夏を愉しむ、若夏の姉御。　　流麗な身体捌きで、始・継・終と、UBを重ねるごとに、加速する。", 350, 2, 95);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (17, 0.043, 105, 113301, 1.5, 1, 0, 17, 117, 0, "夏のトキメキに触れた、オタク魔法少女。多彩な魔法を操り、少しずつ他の走者の速度を落とし続ける。", 130, 3, 105);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (18, 0.018, 105, 113201, 1.5, 1, 0, 18, 118, 0, "海獄に降臨せし、真夏の冥姫。　　レース後半に魔力を全解放し、　　蒼き疾風と成りて浜を駆け抜ける。", 130, 2, 95);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (19, 0.021, 110, 117001, 2.5, 0, 1, 19, 119, 0, "夏の夕を火花で彩る、渚の壊し屋。『壊し屋』の異名と過激な愛情は、対戦相手にプレッシャーを与える。", 160, 2, 108);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (20, 0.036, 110, 113501, 2.5, 0, 0, 20, 120, 1, "青春に生きる者を導く、夏の先生。夢へと邁進する聖母の加護が、その身をあらゆる困難から守る。", 255, 1, 105);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (21, 0.02, 105, 113401, 2.5, 0, 0, 21, 121, 1, "笑顔の応援が眩しい、夏の超能力　ガール。超能力を駆使して、どんな障害物もひとっ飛びで乗り越える。", 350, 3, 105);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (22, 0.018, 110, 110101, 2.5, 1, 0, 22, 122, 0, "海辺で大人の魅力を放つ、夏の　　セクシー先生。その魅力に囚われた対戦相手は、走りを乱してしまう。", 130, 1, 105);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (23, 0.03, 105, 110001, 3.5, 0, 1, 23, 123, 0, "水着も絶対外さない、夏のカリスマモデル。走りのバイブスは超テンアゲで、スピードはおにやば。", 160, 3, 111);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (24, 0.027, 110, 117201, 1.5, 1, 0, 24, 124, 0, "南の島も盛り上げる、真夏のアイドル。悪天候でも笑顔を絶やさず後半もリズムを上げて走り切る。", 130, 1, 103);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (25, 0.02, 105, 117301, 3.5, 0, 1, 25, 125, 0, "海原に美声を響かす、渚の歌姫。　守護の賛歌と精霊の加護により、　障害物から身を守る。", 160, 2, 108);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (26, 0.04, 110, 117401, 2.5, 0, 0, 26, 126, 1, "夏でも天邪鬼な、夕凪のテーラー。張り巡らされた魔法の糸で、他の走者の自由を奪う。", 350, 3, 105);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (27, 0.009, 110, 117101, 3.5, 0, 0, 27, 127, 1, "向日葵が良く似合う、海辺の　　　お姉ちゃん。秘密結社の一員で、　抜群の身体能力が一番の武器。", 350, 1, 105);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (28, 0.022, 120, 122901, 3.5, 0, 0, 28, 128, 1, "渚でおっとり、夏色うさぎっこ。　うさぎさんパワー全開で、ぴょん　ぴょんとコースを跳ね回る。", 255, 1, 105);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (29, 0.028, 110, 122801, 2.5, 1, 0, 29, 129, 0, "無邪気さ弾ける、夏色いたずら娘。砂浜でも、いたずらの準備は万端！レースに大波乱が巻き起こる！？", 130, 3, 105);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (30, 0.023, 105, 122701, 3.5, 0, 1, 30, 130, 0, "海でも真面目な、夏色優等生。　　高めた魔力を解き放ち、一瞬の内に他の走者を置き去りにする。", 130, 2, 108);
